{
  "name": "OCR-to-HTML Pro",
  "description": "A high-precision tabular data extraction engine that converts images of tables into clean, valid HTML code using Gemini 3 Pro.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface OCRResult {
  html: string;
  timestamp: number;
}

export enum AppStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  PROCESSING = 'PROCESSING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const SYSTEM_INSTRUCTION = `Role: You are a specialized OCR-to-HTML engine. Your sole purpose is to extract tabular data from an image and output it as raw HTML code.

Task:
1. Identify the rows and columns in the provided image.
2. Extract the text exactly as written.
3. specific Format: Output a simple HTML table with a border attribute.

Strict Output Rules (You must follow these):
- Start your response immediately with <table border="1">.
- End your response immediately with </table>.
- Use ONLY the tags: <table>, <tr>, <td>, <th> (optional for headers).
- Do NOT use any CSS, <style> tags, class attributes, or id attributes.
- Do NOT wrap the output in markdown code blocks (e.g., do not use \`\`\`html ... \`\`\`).
- Do NOT include <html>, <head>, or <body> tags.
- Do NOT output any conversational text, explanations, or labels (like "Here is the code").`;

export const analyzeTableImage = async (base64Image: string, mimeType: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image.split(',')[1], // Remove prefix if exists
              mimeType: mimeType,
            },
          },
          {
            text: "Please extract the table from this image strictly following the provided role and output rules."
          }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: {
          thinkingBudget: 32768
        },
        // As per instructions, we omit maxOutputTokens when using high thinkingBudget
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("Model returned an empty response.");
    }

    return text.trim();
  } catch (error: any) {
    console.error("Gemini OCR Error:", error);
    if (error.message?.includes("Requested entity was not found")) {
      throw new Error("API Key issue or model access error. Please ensure you are using a valid project key.");
    }
    throw error;
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-2 rounded-lg font-medium transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 focus:ring-indigo-500 shadow-sm",
    secondary: "bg-slate-200 text-slate-800 hover:bg-slate-300 focus:ring-slate-400",
    danger: "bg-red-500 text-white hover:bg-red-600 focus:ring-red-400",
    ghost: "bg-transparent text-slate-600 hover:bg-slate-100 focus:ring-slate-300"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing...
        </>
      ) : children}
    </button>
  );
};

import React, { useState } from 'react';
import { Button } from './Button';

interface ResultViewProps {
  html: string;
  onReset: () => void;
}

export const ResultView: React.FC<ResultViewProps> = ({ html, onReset }) => {
  const [activeTab, setActiveTab] = useState<'preview' | 'code'>('preview');
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(html);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="w-full bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden flex flex-col h-[600px]">
      <div className="bg-slate-50 border-b border-slate-200 px-6 py-4 flex items-center justify-between shrink-0">
        <div className="flex space-x-2">
          <button 
            onClick={() => setActiveTab('preview')}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors ${activeTab === 'preview' ? 'bg-indigo-600 text-white' : 'text-slate-600 hover:bg-slate-200'}`}
          >
            Rendered Table
          </button>
          <button 
            onClick={() => setActiveTab('code')}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors ${activeTab === 'code' ? 'bg-indigo-600 text-white' : 'text-slate-600 hover:bg-slate-200'}`}
          >
            Raw HTML
          </button>
        </div>
        <div className="flex space-x-2">
          <Button variant="ghost" onClick={handleCopy} className="text-xs">
            {copied ? <i className="fas fa-check mr-2"></i> : <i className="fas fa-copy mr-2"></i>}
            {copied ? 'Copied' : 'Copy HTML'}
          </Button>
          <Button variant="secondary" onClick={onReset} className="text-xs">
            <i className="fas fa-undo mr-2"></i>
            Reset
          </Button>
        </div>
      </div>

      <div className="flex-1 overflow-auto p-6 bg-white">
        {activeTab === 'preview' ? (
          <div className="prose prose-slate max-w-none">
            <div 
              className="table-container"
              dangerouslySetInnerHTML={{ __html: html }} 
            />
          </div>
        ) : (
          <pre className="bg-slate-900 text-emerald-400 p-6 rounded-lg font-mono text-sm whitespace-pre-wrap break-all h-full">
            {html}
          </pre>
        )}
      </div>

      <div className="bg-slate-50 border-t border-slate-200 px-6 py-3 shrink-0 flex items-center text-xs text-slate-500">
        <i className="fas fa-info-circle mr-2"></i>
        Extracted with Gemini 3 Pro (Thinking Mode Enabled)
      </div>

      <style>{`
        .table-container table {
          width: 100%;
          border-collapse: collapse;
          margin-bottom: 1rem;
        }
        .table-container td, .table-container th {
          padding: 8px 12px;
          border: 1px solid #cbd5e1;
        }
        .table-container th {
          background-color: #f8fafc;
          font-weight: 600;
        }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { analyzeTableImage } from './services/geminiService';
import { Button } from './components/Button';
import { ResultView } from './components/ResultView';
import { AppStatus } from './types';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [image, setImage] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>('');
  const [result, setResult] = useState<string>('');
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        setImage(base64);
        setMimeType(file.type);
        setError(null);
        setStatus(AppStatus.IDLE);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleExtract = async () => {
    if (!image) return;

    setStatus(AppStatus.PROCESSING);
    setError(null);

    try {
      const htmlResult = await analyzeTableImage(image, mimeType);
      setResult(htmlResult);
      setStatus(AppStatus.SUCCESS);
    } catch (err: any) {
      setError(err.message || 'An unexpected error occurred during extraction.');
      setStatus(AppStatus.ERROR);
    }
  };

  const handleReset = useCallback(() => {
    setImage(null);
    setResult('');
    setStatus(AppStatus.IDLE);
    setError(null);
  }, []);

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-indigo-600 text-white shadow-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
          <div className="flex items-center space-x-4">
            <div className="bg-white p-2 rounded-lg text-indigo-600">
              <i className="fas fa-table text-2xl"></i>
            </div>
            <div>
              <h1 className="text-2xl font-bold tracking-tight">OCR-to-HTML Engine</h1>
              <p className="text-indigo-100 text-sm">Convert table images to raw, valid HTML using Gemini 3 Intelligence</p>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 w-full">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 items-start">

          {/* Left Column: Upload & Preview */}
          <div className="space-y-6">
            <div className="bg-white p-8 rounded-xl shadow-lg border border-slate-200">
              <h2 className="text-lg font-semibold mb-4 flex items-center">
                <i className="fas fa-cloud-upload-alt mr-2 text-indigo-500"></i>
                Source Image
              </h2>

              {!image ? (
                <div className="relative group">
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handleFileChange}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                  />
                  <div className="border-2 border-dashed border-slate-300 group-hover:border-indigo-400 rounded-xl p-12 flex flex-col items-center justify-center transition-colors">
                    <div className="w-16 h-16 bg-indigo-50 text-indigo-500 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                      <i className="fas fa-image text-2xl"></i>
                    </div>
                    <p className="text-slate-600 font-medium">Click or drag image to upload</p>
                    <p className="text-slate-400 text-xs mt-2">Supports JPG, PNG, WEBP</p>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="relative rounded-lg overflow-hidden border border-slate-200 max-h-[400px] flex items-center justify-center bg-slate-50">
                    <img 
                      src={image} 
                      alt="Preview" 
                      className="max-w-full max-h-full object-contain"
                    />
                    <button 
                      onClick={() => { setImage(null); setStatus(AppStatus.IDLE); }}
                      className="absolute top-2 right-2 bg-white/90 hover:bg-white text-slate-800 p-2 rounded-full shadow-md transition-all"
                    >
                      <i className="fas fa-times"></i>
                    </button>
                  </div>

                  <div className="flex flex-col space-y-3">
                    <Button 
                      onClick={handleExtract} 
                      className="w-full py-3"
                      isLoading={status === AppStatus.PROCESSING}
                    >
                      <i className="fas fa-wand-magic-sparkles mr-2"></i>
                      Extract Tabular Data
                    </Button>
                    <Button 
                      variant="ghost" 
                      onClick={handleReset} 
                      className="text-slate-500 text-sm"
                      disabled={status === AppStatus.PROCESSING}
                    >
                      Select Different Image
                    </Button>
                  </div>
                </div>
              )}
            </div>

            {/* Status & Error Messages */}
            {status === AppStatus.PROCESSING && (
              <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-6 animate-pulse">
                <div className="flex items-center space-x-4">
                  <div className="flex-1">
                    <div className="h-2 bg-indigo-200 rounded-full w-3/4 mb-2"></div>
                    <div className="h-2 bg-indigo-200 rounded-full w-1/2"></div>
                  </div>
                </div>
                <p className="mt-4 text-sm text-indigo-700 font-medium flex items-center">
                  <i className="fas fa-brain mr-2 animate-bounce"></i>
                  Gemini is thinking... analyzing rows and columns...
                </p>
              </div>
            )}

            {error && (
              <div className="bg-red-50 border border-red-100 rounded-xl p-6 text-red-700">
                <div className="flex items-start space-x-3">
                  <i className="fas fa-exclamation-triangle mt-1"></i>
                  <div>
                    <h3 className="font-bold">Extraction Failed</h3>
                    <p className="text-sm opacity-90">{error}</p>
                    <Button variant="danger" onClick={handleExtract} className="mt-4 text-xs">
                      Try Again
                    </Button>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Right Column: Results */}
          <div className="space-y-6">
            {status === AppStatus.SUCCESS ? (
              <ResultView html={result} onReset={handleReset} />
            ) : (
              <div className="h-[600px] flex flex-col items-center justify-center bg-slate-100 rounded-xl border border-slate-200 border-dashed text-slate-400">
                <i className="fas fa-code text-5xl mb-4 opacity-20"></i>
                <p className="text-center px-10">
                  Extracted HTML table will appear here after processing.
                </p>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-6 mt-12 shrink-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col md:flex-row justify-between items-center text-slate-500 text-sm">
          <p>© 2024 Specialized OCR Engine. Built with Gemini 3 Pro.</p>
          <div className="flex space-x-6 mt-4 md:mt-0">
            <span className="flex items-center"><i className="fas fa-check-circle text-emerald-500 mr-2"></i> Clean HTML</span>
            <span className="flex items-center"><i className="fas fa-check-circle text-emerald-500 mr-2"></i> Thinking Mode</span>
            <span className="flex items-center"><i className="fas fa-check-circle text-emerald-500 mr-2"></i> 32k Budget</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const SYSTEM_INSTRUCTION = `Role: You are a specialized OCR-to-HTML engine. Your sole purpose is to extract tabular data from an image and output it as raw HTML code.

Task:
1. Identify the rows and columns in the provided image.
2. Extract the text exactly as written.
3. Specific Format: Output a simple HTML table with a border attribute.

Strict Output Rules (You must follow these):
- Start your response immediately with <table border="1">.
- End your response immediately with </table>.
- Use ONLY the tags: <table>, <tr>, <td>, <th> (optional for headers).
- Do NOT use any CSS, <style> tags, class attributes, or id attributes.
- Do NOT wrap the output in markdown code blocks (e.g., do not use \`\`\`html ... \`\`\`).
- Do NOT include <html>, <head>, or <body> tags.
- Do NOT output any conversational text, explanations, or labels.`;

export const analyzeTableImage = async (base64Image: string, mimeType: string, excludedKeywords: string[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  let keywordInstruction = "";
  if (excludedKeywords.length > 0) {
    keywordInstruction = `\n\nCRITICAL FILTERING RULE: Exclude any rows where the text in the first column (the "Label") contains any of these keywords: ${excludedKeywords.join(', ')}. If a row matches an excluded keyword, completely omit its <tr> block from the output.`;
  }

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image.split(',')[1],
              mimeType: mimeType,
            },
          },
          {
            text: `Please extract the table from this image strictly following the provided role and output rules.${keywordInstruction}`
          }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: {
          thinkingBudget: 32768
        },
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("Model returned an empty response.");
    }

    return text.trim();
  } catch (error: any) {
    console.error("Gemini OCR Error:", error);
    if (error.message?.includes("Requested entity was not found")) {
      throw new Error("API Key issue or model access error. Please ensure you are using a valid project key.");
    }
    throw error;
  }
};

import React, { useState, useCallback } from 'react';
import { analyzeTableImage } from './services/geminiService';
import { Button } from './components/Button';
import { ResultView } from './components/ResultView';
import { AppStatus } from './types';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [image, setImage] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>('');
  const [result, setResult] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [keywordsInput, setKeywordsInput] = useState<string>('');

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        setImage(base64);
        setMimeType(file.type);
        setError(null);
        setStatus(AppStatus.IDLE);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleExtract = async () => {
    if (!image) return;

    setStatus(AppStatus.PROCESSING);
    setError(null);

    // Clean keywords: split by comma, trim, filter out empty strings
    const keywords = keywordsInput
      .split(',')
      .map(k => k.trim())
      .filter(k => k.length > 0);

    try {
      const htmlResult = await analyzeTableImage(image, mimeType, keywords);
      setResult(htmlResult);
      setStatus(AppStatus.SUCCESS);
    } catch (err: any) {
      setError(err.message || 'An unexpected error occurred during extraction.');
      setStatus(AppStatus.ERROR);
    }
  };

  const handleReset = useCallback(() => {
    setImage(null);
    setResult('');
    setStatus(AppStatus.IDLE);
    setError(null);
    setKeywordsInput('');
  }, []);

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-indigo-600 text-white shadow-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
          <div className="flex items-center space-x-4">
            <div className="bg-white p-2 rounded-lg text-indigo-600">
              <i className="fas fa-table text-2xl"></i>
            </div>
            <div>
              <h1 className="text-2xl font-bold tracking-tight">OCR-to-HTML Engine</h1>
              <p className="text-indigo-100 text-sm">Extract, filter, and convert tabular images to clean HTML</p>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 w-full">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 items-start">

          {/* Left Column: Upload & Settings */}
          <div className="space-y-6">
            <div className="bg-white p-8 rounded-xl shadow-lg border border-slate-200">
              <h2 className="text-lg font-semibold mb-4 flex items-center">
                <i className="fas fa-sliders-h mr-2 text-indigo-500"></i>
                Extraction Settings
              </h2>

              {!image ? (
                <div className="relative group mb-6">
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handleFileChange}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                  />
                  <div className="border-2 border-dashed border-slate-300 group-hover:border-indigo-400 rounded-xl p-12 flex flex-col items-center justify-center transition-colors">
                    <div className="w-16 h-16 bg-indigo-50 text-indigo-500 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                      <i className="fas fa-image text-2xl"></i>
                    </div>
                    <p className="text-slate-600 font-medium">Click or drag image to upload</p>
                    <p className="text-slate-400 text-xs mt-2">Supports JPG, PNG, WEBP</p>
                  </div>
                </div>
              ) : (
                <div className="space-y-6">
                  <div className="relative rounded-lg overflow-hidden border border-slate-200 max-h-[300px] flex items-center justify-center bg-slate-50">
                    <img 
                      src={image} 
                      alt="Preview" 
                      className="max-w-full max-h-full object-contain"
                    />
                    <button 
                      onClick={() => { setImage(null); setStatus(AppStatus.IDLE); }}
                      className="absolute top-2 right-2 bg-white/90 hover:bg-white text-slate-800 p-2 rounded-full shadow-md transition-all"
                    >
                      <i className="fas fa-times"></i>
                    </button>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-semibold text-slate-700 flex items-center">
                      <i className="fas fa-filter mr-2 text-indigo-400"></i>
                      Exclude Rows (Keywords)
                    </label>
                    <input 
                      type="text"
                      placeholder="e.g. Total, Subtotal, Discount"
                      value={keywordsInput}
                      onChange={(e) => setKeywordsInput(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-sm"
                      disabled={status === AppStatus.PROCESSING}
                    />
                    <p className="text-xs text-slate-400">Separate multiple keywords with commas. Rows with these labels will be omitted.</p>
                  </div>

                  <div className="flex flex-col space-y-3 pt-2">
                    <Button 
                      onClick={handleExtract} 
                      className="w-full py-3"
                      isLoading={status === AppStatus.PROCESSING}
                    >
                      <i className="fas fa-wand-magic-sparkles mr-2"></i>
                      Extract & Filter Data
                    </Button>
                    <Button 
                      variant="ghost" 
                      onClick={handleReset} 
                      className="text-slate-500 text-sm"
                      disabled={status === AppStatus.PROCESSING}
                    >
                      Start Over
                    </Button>
                  </div>
                </div>
              )}
            </div>

            {/* Status & Error Messages */}
            {status === AppStatus.PROCESSING && (
              <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-6 animate-pulse">
                <p className="text-sm text-indigo-700 font-medium flex items-center">
                  <i className="fas fa-brain mr-2 animate-bounce"></i>
                  Gemini is identifying table structure and applying filters...
                </p>
              </div>
            )}

            {error && (
              <div className="bg-red-50 border border-red-100 rounded-xl p-6 text-red-700">
                <div className="flex items-start space-x-3">
                  <i className="fas fa-exclamation-triangle mt-1"></i>
                  <div>
                    <h3 className="font-bold">Extraction Failed</h3>
                    <p className="text-sm opacity-90">{error}</p>
                    <Button variant="danger" onClick={handleExtract} className="mt-4 text-xs">
                      Try Again
                    </Button>
                  </div>
                </div>
              </div>
            )}
          </div>

