import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { analyzeTableImage } from './services/geminiService';
import { Button } from './components/Button';
import { ResultView } from './components/ResultView';
import { AppStatus, StoredTable } from './types';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [image, setImage] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>('');
  const [result, setResult] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [keywordsInput, setKeywordsInput] = useState<string>('');

  // Gallery State
  const [gallery, setGallery] = useState<StoredTable[]>(() => {
    const saved = localStorage.getItem('ocr_gallery');
    return saved ? JSON.parse(saved) : [];
  });

  const [showCombined, setShowCombined] = useState(false);

  // Persistence
  useEffect(() => {
    localStorage.setItem('ocr_gallery', JSON.stringify(gallery));
  }, [gallery]);

  const handleFile = (file: File) => {
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        setImage(base64);
        setMimeType(file.type);
        setError(null);
        setStatus(AppStatus.IDLE);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  useEffect(() => {
    const handlePaste = (event: ClipboardEvent) => {
      const items = event.clipboardData?.items;
      if (items) {
        for (let i = 0; i < items.length; i++) {
          if (items[i].type.indexOf('image') !== -1) {
            const file = items[i].getAsFile();
            if (file) handleFile(file);
            break;
          }
        }
      }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, []);

  const handleExtract = async () => {
    if (!image) return;
    setStatus(AppStatus.PROCESSING);
    setError(null);
    try {
      const htmlResult = await analyzeTableImage(image, mimeType, keywordsInput);
      setResult(htmlResult);
      setStatus(AppStatus.SUCCESS);
    } catch (err: any) {
      setError(err.message || 'An unexpected error occurred during extraction.');
      setStatus(AppStatus.ERROR);
    }
  };

  const handleStore = () => {
    if (!result) return;
    const newEntry: StoredTable = {
      id: crypto.randomUUID(),
      html: result,
      timestamp: Date.now()
    };
    setGallery(prev => [newEntry, ...prev]);
    // Optional: Reset current view to show gallery focus
    setImage(null);
    setResult('');
    setStatus(AppStatus.IDLE);
  };

  const handleDeleteAll = () => {
    if (window.confirm('Are you sure you want to delete all stored tables? This action cannot be undone.')) {
      setGallery([]);
      setShowCombined(false);
    }
  };

  const deleteItem = (id: string) => {
    setGallery(prev => prev.filter(item => item.id !== id));
  };

  const combinedHtml = useMemo(() => {
    if (gallery.length === 0) return "";

    const parser = new DOMParser();
    const dataMap = new Map<string, string[]>();
    let maxColumns = 0;

    gallery.forEach(item => {
      const doc = parser.parseFromString(item.html, 'text/html');
      const rows = doc.querySelectorAll('tr');

      rows.forEach(row => {
        const cells = Array.from(row.querySelectorAll('td, th'));
        if (cells.length === 0) return;

        const label = (cells[0].textContent || '').trim();
        if (!label) return;

        // Skip if label is just a header that isn't data
        const values = cells.slice(1).map(c => (c.textContent || '').trim());
        maxColumns = Math.max(maxColumns, values.length);

        if (!dataMap.has(label)) {
          dataMap.set(label, values);
        } else {
          const existing = dataMap.get(label)!;
          // Combine existing column values with commas
          const combined = existing.map((val, idx) => {
            const newVal = values[idx] || "";
            if (!val) return newVal;
            if (!newVal) return val;
            return `${val}, ${newVal}`;
          });
          // If the new row has more columns than previously stored for this label
          if (values.length > existing.length) {
            combined.push(...values.slice(existing.length));
          }
          dataMap.set(label, combined);
        }
      });
    });

    let html = '<table border="1"><thead><tr><th>Label</th>';
    for (let i = 0; i < maxColumns; i++) {
      html += `<th>Value ${i + 1}</th>`;
    }
    html += '</tr></thead><tbody>';

    dataMap.forEach((values, label) => {
      html += `<tr><td>${label}</td>`;
      for (let i = 0; i < maxColumns; i++) {
        html += `<td>${values[i] || ""}</td>`;
      }
      html += '</tr>';
    });

    html += '</tbody></table>';
    return html;
  }, [gallery]);

  const handleReset = useCallback(() => {
    setImage(null);
    setResult('');
    setStatus(AppStatus.IDLE);
    setError(null);
    setKeywordsInput('');
  }, []);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      {/* Header */}
      <header className="bg-indigo-600 text-white shadow-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-3">
            <div className="bg-white p-2 rounded-lg text-indigo-600">
              <i className="fas fa-bolt text-xl"></i>
            </div>
            <h1 className="text-xl font-bold tracking-tight hidden sm:block">OCR-to-HTML Fast</h1>
          </div>
          <div className="flex space-x-4">
             <a href="#gallery" className="text-sm font-medium hover:text-indigo-200 transition-colors">
               <i className="fas fa-images mr-2"></i>Gallery ({gallery.length})
             </a>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full space-y-12">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">

          {/* Left Column: Inputs */}
          <div className="space-y-6">
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
              <h2 className="text-lg font-semibold mb-6 flex items-center text-slate-800">
                <i className="fas fa-cog mr-2 text-indigo-500"></i>
                Extraction Setup
              </h2>

              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center">
                    <i className="fas fa-filter mr-2 text-indigo-400"></i>
                    Exclude Keywords
                  </label>
                  <input 
                    type="text"
                    placeholder="e.g. Total, Grand Total, Tax"
                    value={keywordsInput}
                    onChange={(e) => setKeywordsInput(e.target.value)}
                    className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-sm shadow-sm"
                    disabled={status === AppStatus.PROCESSING}
                  />
                </div>

                {!image ? (
                  <div className="relative group">
                    <input
                      type="file"
                      accept="image/*"
                      onChange={handleFileChange}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                    />
                    <div className="border-2 border-dashed border-slate-200 group-hover:border-indigo-400 group-hover:bg-indigo-50 rounded-xl p-10 flex flex-col items-center justify-center transition-all bg-slate-50">
                      <div className="w-12 h-12 bg-white text-indigo-500 rounded-full flex items-center justify-center mb-3 shadow-sm">
                        <i className="fas fa-plus"></i>
                      </div>
                      <p className="text-slate-600 text-sm font-semibold">Drop image or Paste (Ctrl+V)</p>
                      <p className="text-slate-400 text-xs mt-1 text-center">Standard formats supported</p>
                    </div>
                  </div>
                ) : (
                  <div className="space-y-4">
                    <div className="relative rounded-lg overflow-hidden border border-slate-200 max-h-[300px] flex items-center justify-center bg-slate-100 shadow-inner">
                      <img src={image} alt="Preview" className="max-w-full max-h-full object-contain" />
                      <button 
                        onClick={() => { setImage(null); setStatus(AppStatus.IDLE); }}
                        className="absolute top-2 right-2 bg-red-500 hover:bg-red-600 text-white p-2 rounded-full shadow-lg transition-all"
                      >
                        <i className="fas fa-times text-xs"></i>
                      </button>
                    </div>

                    <div className="flex flex-col space-y-2">
                      <Button onClick={handleExtract} className="w-full py-4 text-base shadow-lg" isLoading={status === AppStatus.PROCESSING}>
                        <i className="fas fa-play-circle mr-2"></i>
                        Run Extraction
                      </Button>
                      <Button variant="ghost" onClick={handleReset} className="text-slate-400 text-xs uppercase font-bold" disabled={status === AppStatus.PROCESSING}>
                        Reset Input
                      </Button>
                    </div>
                  </div>
                )}
              </div>
            </div>

            {status === AppStatus.PROCESSING && (
              <div className="bg-emerald-600 text-white rounded-xl p-6 shadow-xl animate-pulse">
                <div className="flex items-center space-x-4">
                  <i className="fas fa-spinner fa-spin text-2xl"></i>
                  <div>
                    <p className="font-bold">Fast Engine Active</p>
                    <p className="text-emerald-100 text-sm">Processing with high accuracy...</p>
                  </div>
                </div>
              </div>
            )}

            {error && (
              <div className="bg-red-50 border-l-4 border-red-500 p-4 text-red-700 rounded-r-xl shadow-md">
                <div className="flex">
                  <i className="fas fa-exclamation-circle mr-3 mt-1"></i>
                  <p className="text-sm font-medium">{error}</p>
                </div>
              </div>
            )}
          </div>

          {/* Right Column: Results */}
          <div className="space-y-6">
            {status === AppStatus.SUCCESS ? (
              <ResultView html={result} onReset={handleReset} onStore={handleStore} />
            ) : (
              <div className="h-[550px] flex flex-col items-center justify-center bg-white rounded-xl border border-slate-200 border-dashed text-slate-300 shadow-sm">
                <div className="bg-slate-50 p-6 rounded-full mb-6">
                  <i className="fas fa-table text-5xl opacity-20"></i>
                </div>
                <h3 className="text-slate-500 font-semibold">Active Workspace</h3>
                <p className="text-center px-12 text-sm mt-2">
                  Extracted data will be rendered here for verification before storage.
                </p>
              </div>
            )}
          </div>
        </div>

        {/* Text Gallery Section */}
        <section id="gallery" className="pt-8 border-t border-slate-200">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
            <div>
              <h2 className="text-2xl font-bold text-slate-800 flex items-center">
                <i className="fas fa-layer-group mr-3 text-indigo-500"></i>
                Text Gallery
              </h2>
              <p className="text-slate-500 text-sm">Stored extraction history and combined insights</p>
            </div>

            <div className="flex flex-wrap gap-3">
              <Button 
                variant="primary" 
                onClick={() => setShowCombined(true)} 
                disabled={gallery.length < 2}
                className="!bg-indigo-700 hover:!bg-indigo-800"
              >
                <i className="fas fa-compress-alt mr-2"></i>
                Combine All Data
              </Button>
              <Button variant="danger" onClick={handleDeleteAll} disabled={gallery.length === 0}>
                <i className="fas fa-trash mr-2"></i>
                Clear Gallery
              </Button>
            </div>
          </div>

          {showCombined && (
            <div className="mb-12 bg-indigo-50 p-6 rounded-2xl border-2 border-indigo-200 shadow-xl relative animate-in fade-in duration-500">
              <button 
                onClick={() => setShowCombined(false)}
                className="absolute top-4 right-4 text-indigo-400 hover:text-indigo-600"
              >
                <i className="fas fa-times-circle text-xl"></i>
              </button>
              <h3 className="text-indigo-800 font-bold mb-4 flex items-center">
                <i className="fas fa-magic mr-2"></i>
                Combined Data Table
              </h3>
              <div className="bg-white rounded-xl p-4 overflow-auto border border-indigo-100 max-h-[500px] shadow-inner">
                <style>{`
                  .combined-table table { width: 100%; border-collapse: collapse; }
                  .combined-table td, .combined-table th { padding: 10px; border: 1px solid #e2e8f0; font-size: 13px; }
                  .combined-table th { background: #f8fafc; color: #475569; text-align: left; }
                `}</style>
                <div className="combined-table" dangerouslySetInnerHTML={{ __html: combinedHtml }} />
              </div>
              <div className="mt-4 flex justify-end">
                <Button variant="ghost" onClick={() => navigator.clipboard.writeText(combinedHtml)} className="text-indigo-600 bg-white">
                  <i className="fas fa-copy mr-2"></i> Copy Combined HTML
                </Button>
              </div>
            </div>
          )}

          {gallery.length === 0 ? (
            <div className="bg-white rounded-2xl p-16 flex flex-col items-center justify-center border border-slate-200 shadow-sm border-dashed">
              <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                <i className="fas fa-folder-open text-slate-300 text-2xl"></i>
              </div>
              <p className="text-slate-400 text-sm">Your gallery is currently empty.</p>
              <p className="text-slate-400 text-xs mt-1">Extract and "Store" items to see them here.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
              {gallery.map((item) => (
                <div key={item.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col group hover:shadow-md transition-shadow">
                  <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex justify-between items-center shrink-0">
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                      {new Date(item.timestamp).toLocaleString()}
                    </span>
                    <button 
                      onClick={() => deleteItem(item.id)}
                      className="text-slate-400 hover:text-red-500 transition-colors p-1"
                    >
                      <i className="fas fa-times"></i>
                    </button>
                  </div>
                  <div className="p-4 flex-1 overflow-auto max-h-[250px] relative">
                    <style>{`
                      .gallery-preview table { font-size: 11px; width: 100%; border-collapse: collapse; }
                      .gallery-preview td, .gallery-preview th { padding: 4px 6px; border: 1px solid #e2e8f0; }
                    `}</style>
                    <div className="gallery-preview" dangerouslySetInnerHTML={{ __html: item.html }} />
                  </div>
                  <div className="p-3 bg-slate-50/50 border-t border-slate-200 flex justify-end">
                    <Button variant="ghost" className="text-[10px] py-1 h-auto" onClick={() => navigator.clipboard.writeText(item.html)}>
                       <i className="fas fa-copy mr-1"></i> Copy HTML
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>
      </main>

      {/* Footer */}
      <footer className="bg-slate-900 text-slate-400 py-8 mt-12 shrink-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col md:flex-row justify-between items-center text-xs">
          <div className="flex items-center space-x-2">
             <div className="bg-emerald-500 w-2 h-2 rounded-full animate-pulse"></div>
             <p>Gemini 3 Flash Extraction Suite v3.0</p>
          </div>
          <p className="mt-4 md:mt-0 opacity-50">Local data storage enabled • Privacy focused</p>
        </div>
      </footer>
    </div>
  );
};

