                    `}</style>
                    <div className="gallery-preview" dangerouslySetInnerHTML={{ __html: item.html }} />
                  </div>
                  <div className="p-3 bg-slate-50/50 border-t border-slate-200 flex justify-end">
                    <Button variant="ghost" className="text-[10px] py-1 h-auto" onClick={() => navigator.clipboard.writeText(item.html)}>
                       <i className="fas fa-copy mr-1"></i> Copy HTML
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>
      </main>

      {/* Footer */}
      <footer className="bg-slate-900 text-slate-400 py-8 mt-12 shrink-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col md:flex-row justify-between items-center text-xs">
          <div className="flex items-center space-x-2">
             <div className="bg-emerald-500 w-2 h-2 rounded-full animate-pulse"></div>
             <p>Gemini 3 Flash Extraction Suite v3.2</p>
          </div>
          <p className="mt-4 md:mt-0 opacity-50">Auto-save Enabled • Safe Deletion Active</p>
        </div>
      </footer>
