                  <Button variant="danger" onClick={executeDeleteAll} className="!py-1.5 !px-4 text-[10px] font-black uppercase tracking-widest">
                    YES
                  </Button>
                  <Button variant="ghost" onClick={() => setIsConfirmingDelete(false)} className="!py-1.5 !px-4 text-[10px] font-black uppercase tracking-widest">
                    NO
                  </Button>
                </div>
              )}
            </div>
          </div>

          {showCombined && (
            <div className="bg-indigo-600 rounded-3xl p-10 shadow-2xl shadow-indigo-200 relative animate-in fade-in slide-in-from-top-4 duration-500">
              <div className="flex justify-between items-start mb-8">
                <div>
                  <h3 className="text-white text-2xl font-black tracking-tight mb-2">Combined Intelligence</h3>
                  <p className="text-indigo-100 text-sm font-medium">Cross-referenced unique values from all stored records.</p>
                </div>
                <button onClick={() => setShowCombined(false)} className="text-white/40 hover:text-white transition-colors">
                  <i className="fas fa-times-circle text-2xl"></i>
                </button>
              </div>

              <div className="bg-white/10 backdrop-blur-xl rounded-2xl p-8 overflow-auto border border-white/20 max-h-[500px] shadow-inner custom-scrollbar">
                <style>{`
                  .combined-table table { width: 100%; border-collapse: collapse; color: white; }
                  .combined-table td, .combined-table th { padding: 14px 20px; border: 1px solid rgba(255,255,255,0.1); font-size: 13px; font-weight: 500; }
                  .combined-table th { background: rgba(255,255,255,0.05); color: rgba(255,255,255,0.9); text-align: left; font-weight: 800; text-transform: uppercase; font-size: 11px; letter-spacing: 0.1em; }
                `}</style>
                <div className="combined-table" dangerouslySetInnerHTML={{ __html: combinedHtml }} />
              </div>

              <div className="mt-8 flex justify-end">
                <Button variant="secondary" onClick={() => navigator.clipboard.writeText(combinedHtml)} className="!rounded-xl font-black text-xs tracking-widest">
                  <i className="fas fa-copy mr-2"></i> EXPORT TABLE
                </Button>
              </div>
            </div>
          )}

          {gallery.length === 0 ? (
            <div className="bg-white rounded-3xl p-24 flex flex-col items-center justify-center border border-slate-200 border-dashed text-slate-300">
              <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-6">
                <i className="fas fa-database text-3xl opacity-20"></i>
              </div>
              <p className="font-black text-sm uppercase tracking-widest">No Records Found</p>
              <p className="text-xs mt-2 font-medium">Extractions will appear here automatically.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-8">
              {gallery.map((item) => (
                <div key={item.id} className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden flex flex-col group hover:shadow-xl hover:-translate-y-1 transition-all duration-300 animate-in fade-in zoom-in duration-300">
                  <div className="bg-slate-50/80 px-6 py-4 border-b border-slate-200 flex justify-between items-center shrink-0">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                      {new Date(item.timestamp).toLocaleDateString()} at {new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                    </span>
                    <button 
                      onClick={() => deleteItem(item.id)}
                      className="text-slate-300 hover:text-rose-500 transition-colors p-1"
                    >
                      <i className="fas fa-times-circle"></i>
                    </button>
                  </div>
                  <div className="p-6 flex-1 overflow-auto max-h-[300px] relative custom-scrollbar bg-white">
                    <style>{`
                      .gallery-preview table { font-size: 11px; width: 100%; border-collapse: collapse; }
                      .gallery-preview td, .gallery-preview th { padding: 6px 10px; border: 1px solid #f1f5f9; font-weight: 500; }
                      .gallery-preview th { font-weight: 800; color: #64748b; background: #f8fafc; text-transform: uppercase; font-size: 9px; }
                    `}</style>
                    <div className="gallery-preview" dangerouslySetInnerHTML={{ __html: item.html }} />
                  </div>
                  <div className="px-6 py-4 bg-slate-50/30 border-t border-slate-100 flex justify-between items-center">
                    <div className="text-[10px] font-bold text-slate-400 uppercase">Snapshot</div>
                    <Button variant="ghost" className="!p-2 h-8 w-8 !rounded-lg" onClick={() => navigator.clipboard.writeText(item.html)}>
                       <i className="fas fa-copy text-xs"></i>
