export default App;

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { analyzeTableImage } from './services/geminiService';
import { Button } from './components/Button';
import { ResultView } from './components/ResultView';
import { AppStatus, StoredTable } from './types';

type ViewType = 'workspace' | 'gallery';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('workspace');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [image, setImage] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>('');
  const [result, setResult] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [keywordsInput, setKeywordsInput] = useState<string>('');
  const [isConfirmingDelete, setIsConfirmingDelete] = useState(false);

  // Gallery State
  const [gallery, setGallery] = useState<StoredTable[]>(() => {
    try {
      const saved = localStorage.getItem('ocr_gallery');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [showCombined, setShowCombined] = useState(false);

  useEffect(() => {
    localStorage.setItem('ocr_gallery', JSON.stringify(gallery));
  }, [gallery]);

  const handleFile = (file: File) => {
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        setImage(base64);
        setMimeType(file.type);
        setError(null);
        setStatus(AppStatus.IDLE);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  useEffect(() => {
    const handlePaste = (event: ClipboardEvent) => {
      const items = event.clipboardData?.items;
      if (items) {
        for (let i = 0; i < items.length; i++) {
          if (items[i].type.indexOf('image') !== -1) {
            const file = items[i].getAsFile();
            if (file) handleFile(file);
            break;
          }
        }
      }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, []);

  const handleExtract = async () => {
    if (!image) return;
    setStatus(AppStatus.PROCESSING);
    setError(null);
    try {
      const htmlResult = await analyzeTableImage(image, mimeType, keywordsInput);
      setResult(htmlResult);
      setStatus(AppStatus.SUCCESS);

      const newEntry: StoredTable = {
        id: crypto.randomUUID(),
        html: htmlResult,
        timestamp: Date.now()
      };
      setGallery(prev => [newEntry, ...prev]);
    } catch (err: any) {
      setError(err.message || 'Extraction failed. Please check your image or API key.');
      setStatus(AppStatus.ERROR);
    }
  };

  const executeDeleteAll = () => {
    setGallery([]);
    setShowCombined(false);
    setIsConfirmingDelete(false);
    localStorage.removeItem('ocr_gallery');
  };

  const deleteItem = (id: string) => {
    setGallery(prev => prev.filter(item => item.id !== id));
  };

  const combinedHtml = useMemo(() => {
    if (gallery.length === 0) return "";
    const parser = new DOMParser();
    const dataMap = new Map<string, Set<string>[]>();
    let maxColumns = 0;

    gallery.forEach(item => {
      const doc = parser.parseFromString(item.html, 'text/html');
      const rows = doc.querySelectorAll('tr');
      rows.forEach(row => {
        const cells = Array.from(row.querySelectorAll('td, th'));
        if (cells.length === 0) return;
        const label = (cells[0].textContent || '').trim();
        if (!label) return;
        const values = cells.slice(1).map(c => (c.textContent || '').trim());
        maxColumns = Math.max(maxColumns, values.length);
        if (!dataMap.has(label)) {
          dataMap.set(label, values.map(v => new Set(v ? [v] : [])));
        } else {
          const existingSets = dataMap.get(label)!;
          values.forEach((val, idx) => {
            if (!val) return;
            if (idx >= existingSets.length) {
              existingSets.push(new Set([val]));
            } else {
              existingSets[idx].add(val);
            }
          });
        }
      });
    });

    let html = '<table border="1"><thead><tr><th>Label</th>';
    for (let i = 0; i < maxColumns; i++) {
      html += `<th>Combined Value ${i + 1}</th>`;
    }
    html += '</tr></thead><tbody>';
    dataMap.forEach((columnSets, label) => {
      html += `<tr><td>${label}</td>`;
      for (let i = 0; i < maxColumns; i++) {
        const values = columnSets[i] ? Array.from(columnSets[i]) : [];
        html += `<td>${values.join(', ')}</td>`;
      }
      html += '</tr>';
    });
    html += '</tbody></table>';
    return html;
  }, [gallery]);

  const handleReset = useCallback(() => {
    setImage(null);
    setResult('');
    setStatus(AppStatus.IDLE);
    setError(null);
  }, []);

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 selection:bg-indigo-100 flex flex-col font-sans">
      {/* Tab-based Header */}
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-[1600px] mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-200">
              <i className="fas fa-layer-group text-lg"></i>
            </div>
            <div>
              <h1 className="text-xl font-black tracking-tight text-slate-900">STUDIO<span className="text-indigo-600">OCR</span></h1>
              <div className="flex items-center text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                <span className="w-2 h-2 rounded-full bg-emerald-500 mr-2"></span>
                v3.5 Engine Active
              </div>
            </div>
          </div>

          <nav className="flex items-center space-x-2 md:space-x-8">
            <button 
              onClick={() => setActiveView('workspace')}
              className={`text-sm font-black transition-all px-4 py-2 rounded-xl ${activeView === 'workspace' ? 'text-indigo-600 bg-indigo-50' : 'text-slate-500 hover:text-indigo-600'}`}
            >
              WORKSPACE
            </button>
            <button 
              onClick={() => setActiveView('gallery')}
              className={`text-sm font-black transition-all px-4 py-2 rounded-xl flex items-center ${activeView === 'gallery' ? 'text-indigo-600 bg-indigo-50' : 'text-slate-500 hover:text-indigo-600'}`}
            >
              GALLERY
              <span className={`ml-2 px-2 py-0.5 rounded-full text-[10px] ${activeView === 'gallery' ? 'bg-indigo-600 text-white' : 'bg-indigo-100 text-indigo-600'}`}>
                {gallery.length}
              </span>
            </button>
            <div className="hidden md:block h-6 w-px bg-slate-200"></div>
            <Button variant="soft" className="hidden md:flex text-xs font-black">PRO VERSION</Button>
          </nav>
        </div>
      </header>

      <main className="flex-1 max-w-[1600px] mx-auto w-full px-6 py-10">
        {activeView === 'workspace' ? (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Workspace Grid */}
            <section id="workspace" className="grid grid-cols-1 xl:grid-cols-12 gap-10">

              {/* Controls - XL 4 columns */}
              <div className="xl:col-span-4 space-y-8">
                <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm">
                  <div className="flex items-center justify-between mb-8">
                    <h3 className="text-sm font-black text-slate-900 uppercase tracking-wider">Configuration</h3>
                    <i className="fas fa-sliders-h text-slate-300"></i>
                  </div>

                  <div className="space-y-6">
                    <div>
                      <label className="block text-[11px] font-black text-slate-400 uppercase tracking-widest mb-3">Filter Keywords</label>
                      <div className="relative">
                        <input 
                          type="text"
                          placeholder="e.g. Total, Tax, Sum"
                          value={keywordsInput}
                          onChange={(e) => setKeywordsInput(e.target.value)}
                          className="w-full pl-4 pr-10 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all text-sm font-medium"
                        />
                        <i className="fas fa-search absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 text-xs"></i>
                      </div>
                      <p className="mt-2 text-[10px] text-slate-400 font-medium leading-relaxed italic">
                        Rows containing these labels will be excluded from the extraction.
                      </p>
                    </div>

                    <div className="pt-4">
                      {!image ? (
                        <div className="relative group">
                          <input type="file" accept="image/*" onChange={handleFileChange} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" />
                          <div className="border-2 border-dashed border-slate-200 group-hover:border-indigo-400 group-hover:bg-indigo-50/50 rounded-3xl p-12 flex flex-col items-center justify-center transition-all bg-slate-50/50">
                            <div className="w-14 h-14 bg-white text-indigo-500 rounded-2xl flex items-center justify-center mb-5 shadow-sm group-hover:scale-110 transition-transform">
                              <i className="fas fa-plus text-lg"></i>
                            </div>
                            <p className="text-slate-900 text-sm font-black uppercase tracking-tight">Drop Source Image</p>
                            <p className="text-slate-400 text-xs mt-2 font-medium">Or paste (Ctrl+V) directly</p>
                          </div>
                        </div>
                      ) : (
                        <div className="space-y-6">
                          <div className="relative rounded-3xl overflow-hidden border border-slate-200 aspect-[4/3] flex items-center justify-center bg-slate-100 shadow-inner group">
                            <img src={image} alt="Preview" className="max-w-full max-h-full object-contain" />
                            <div className="absolute inset-0 bg-slate-900/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center backdrop-blur-sm">
                               <Button variant="danger" onClick={() => { setImage(null); setStatus(AppStatus.IDLE); }} className="!rounded-full w-12 h-12 !p-0">
                                  <i className="fas fa-trash"></i>
                               </Button>
                            </div>
                          </div>
                          <Button 
                            onClick={handleExtract} 
                            className="w-full py-5 text-sm font-black uppercase tracking-widest shadow-xl shadow-indigo-100" 
                            isLoading={status === AppStatus.PROCESSING}
                          >
                            Start Extraction
                          </Button>
                        </div>
                      )}
                    </div>
                  </div>
                </div>

                {error && (
                  <div className="bg-rose-50 border border-rose-100 p-5 rounded-2xl flex items-start space-x-4 animate-in slide-in-from-left-4 duration-300">
                    <div className="w-8 h-8 rounded-full bg-rose-500 text-white flex items-center justify-center shrink-0">
                      <i className="fas fa-times text-xs"></i>
                    </div>
                    <div>
                      <h4 className="text-sm font-black text-rose-900 uppercase tracking-tight">Processing Error</h4>
                      <p className="text-xs text-rose-700 font-medium mt-1 leading-relaxed">{error}</p>
                    </div>
                  </div>
                )}
              </div>

              {/* Result View - XL 8 columns */}
              <div className="xl:col-span-8 h-full">
                {status === AppStatus.SUCCESS ? (
                  <ResultView html={result} onReset={handleReset} onStore={() => {}} isAutoSaved={true} />
                ) : (
                  <div className="h-[600px] flex flex-col items-center justify-center bg-white rounded-3xl border border-slate-200 border-dashed text-slate-300 shadow-sm relative overflow-hidden">
                    <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#4f46e5 1px, transparent 0)', backgroundSize: '24px 24px' }}></div>
                    <div className="bg-slate-50 p-10 rounded-full mb-8 relative">
                       <i className="fas fa-file-invoice text-7xl text-slate-200"></i>
                       {status === AppStatus.PROCESSING && (
                         <div className="absolute inset-0 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                       )}
                    </div>
                    <h3 className="text-slate-800 font-black uppercase tracking-widest text-sm">Visual Terminal</h3>
                    <p className="text-center px-24 text-xs mt-3 text-slate-400 font-medium leading-relaxed">
                      Upload an image to start the high-speed extraction engine.
                      Results will be auto-saved to your local history.
                    </p>
                    {status === AppStatus.PROCESSING && (
                      <div className="mt-8 px-4 py-2 bg-indigo-600 text-white text-[10px] font-black rounded-full uppercase tracking-widest animate-pulse">
                        Analyzing Pixels...
                      </div>
                    )}
                  </div>
                )}
              </div>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 space-y-10">
            {/* Gallery Section */}
            <div className="flex flex-col md:flex-row justify-between items-end gap-6">
              <div className="space-y-2">
                <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Text Gallery</h2>
                <p className="text-slate-400 font-medium text-sm">Review, compare, and manage your local extraction history.</p>
              </div>

              <div className="flex items-center space-x-4">
                {!isConfirmingDelete ? (
                  <>
                    <Button 
                      variant="soft" 
                      onClick={() => setShowCombined(!showCombined)} 
                      disabled={gallery.length < 2}
                      className="!rounded-2xl font-black text-xs uppercase"
                    >
                      <i className="fas fa-layer-group mr-2"></i>
                      {showCombined ? 'Hide Insights' : 'Combined Data'}
                    </Button>
                    <Button variant="ghost" onClick={() => setIsConfirmingDelete(true)} disabled={gallery.length === 0} className="font-black text-xs uppercase">
                      Clear Data
                    </Button>
                  </>
                ) : (
                  <div className="flex items-center space-x-3 bg-rose-50 border border-rose-200 p-2 rounded-2xl animate-in fade-in zoom-in duration-200">
                    <span className="text-rose-900 text-[10px] font-black uppercase tracking-widest px-2">Erase all?</span>
                    <Button variant="danger" onClick={executeDeleteAll} className="!py-1.5 !px-4 text-[10px] font-black uppercase tracking-widest">
                      YES
                    </Button>
                    <Button variant="ghost" onClick={() => setIsConfirmingDelete(false)} className="!py-1.5 !px-4 text-[10px] font-black uppercase tracking-widest">
                      NO
                    </Button>
                  </div>
                )}
              </div>
            </div>

            {showCombined && (
              <div className="bg-indigo-600 rounded-3xl p-10 shadow-2xl shadow-indigo-200 relative animate-in fade-in slide-in-from-top-4 duration-500">
                <div className="flex justify-between items-start mb-8">
                  <div>
                    <h3 className="text-white text-2xl font-black tracking-tight mb-2">Combined Intelligence</h3>
                    <p className="text-indigo-100 text-sm font-medium">Cross-referenced unique values from all stored records.</p>
                  </div>
                  <button onClick={() => setShowCombined(false)} className="text-white/40 hover:text-white transition-colors">
                    <i className="fas fa-times-circle text-2xl"></i>
                  </button>
                </div>

                <div className="bg-white/10 backdrop-blur-xl rounded-2xl p-8 overflow-auto border border-white/20 max-h-[500px] shadow-inner custom-scrollbar">
                  <style>{`
                    .combined-table table { width: 100%; border-collapse: collapse; color: white; }
                    .combined-table td, .combined-table th { padding: 14px 20px; border: 1px solid rgba(255,255,255,0.1); font-size: 13px; font-weight: 500; }
                    .combined-table th { background: rgba(255,255,255,0.05); color: rgba(255,255,255,0.9); text-align: left; font-weight: 800; text-transform: uppercase; font-size: 11px; letter-spacing: 0.1em; }
                  `}</style>
                  <div className="combined-table" dangerouslySetInnerHTML={{ __html: combinedHtml }} />
                </div>

                <div className="mt-8 flex justify-end">
                  <Button variant="secondary" onClick={() => navigator.clipboard.writeText(combinedHtml)} className="!rounded-xl font-black text-xs tracking-widest">
                    <i className="fas fa-copy mr-2"></i> EXPORT TABLE
                  </Button>
                </div>
              </div>
            )}

            {gallery.length === 0 ? (
              <div className="bg-white rounded-3xl p-24 flex flex-col items-center justify-center border border-slate-200 border-dashed text-slate-300">
                <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-6">
                  <i className="fas fa-database text-3xl opacity-20"></i>
                </div>
                <p className="font-black text-sm uppercase tracking-widest text-slate-500">No Records Found</p>
                <p className="text-xs mt-2 font-medium">Extractions will appear here automatically.</p>
                <Button variant="primary" onClick={() => setActiveView('workspace')} className="mt-8">
                  GO TO WORKSPACE
                </Button>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-8">
                {gallery.map((item) => (
                  <div key={item.id} className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden flex flex-col group hover:shadow-xl hover:-translate-y-1 transition-all duration-300 animate-in fade-in zoom-in duration-300">
                    <div className="bg-slate-50/80 px-6 py-4 border-b border-slate-200 flex justify-between items-center shrink-0">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                        {new Date(item.timestamp).toLocaleDateString()} at {new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                      </span>
                      <button 
                        onClick={() => deleteItem(item.id)}
                        className="text-slate-300 hover:text-rose-500 transition-colors p-1"
                      >
                        <i className="fas fa-times-circle"></i>
                      </button>
                    </div>
                    <div className="p-6 flex-1 overflow-auto max-h-[300px] relative custom-scrollbar bg-white">
                      <style>{`
                        .gallery-preview table { font-size: 11px; width: 100%; border-collapse: collapse; }
                        .gallery-preview td, .gallery-preview th { padding: 6px 10px; border: 1px solid #f1f5f9; font-weight: 500; }
                        .gallery-preview th { font-weight: 800; color: #64748b; background: #f8fafc; text-transform: uppercase; font-size: 9px; }
                      `}</style>
                      <div className="gallery-preview" dangerouslySetInnerHTML={{ __html: item.html }} />
                    </div>
                    <div className="px-6 py-4 bg-slate-50/30 border-t border-slate-100 flex justify-between items-center">
                      <div className="text-[10px] font-bold text-slate-400 uppercase">Snapshot</div>
                      <Button variant="ghost" className="!p-2 h-8 w-8 !rounded-lg" onClick={() => navigator.clipboard.writeText(item.html)}>
                         <i className="fas fa-copy text-xs"></i>
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-12 shrink-0">
        <div className="max-w-[1600px] mx-auto px-6 flex flex-col md:flex-row justify-between items-center text-[11px] font-bold text-slate-400 tracking-widest uppercase">
          <div className="flex items-center space-x-6">
             <div className="flex items-center">
               <span className="w-2 h-2 rounded-full bg-emerald-500 mr-2"></span>
               Live System
             </div>
             <p>STUDIO OCR V3.5.2 PRO</p>
          </div>
          <div className="flex space-x-8 mt-6 md:mt-0">
            <a href="#" className="hover:text-indigo-600">Privacy</a>
            <a href="#" className="hover:text-indigo-600">Terms</a>
            <a href="#" className="hover:text-indigo-600">API Documentation</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

